const extractNode = $('Extract Closing Data').first();
const doc = extractNode.json.data || extractNode.json;

const previousDocs = $('Get Previous Docs').all();
const triggerData  = $('New Closing Doc').item.json;
const fileName     = triggerData.name || 'unknown';
const fileId       = triggerData.id   || '';

const docType      = doc.documentType  || 'Unknown';
const fileNumber   = doc.fileNumber    || 'N/A';
const purchasePrice= parseFloat(doc.purchasePrice)    || 0;
const loanAmount   = parseFloat(doc.loanAmount)       || 0;
const cashToClose  = parseFloat(doc.cashToClose)      || 0;
const closingCosts = parseFloat(doc.totalClosingCosts)|| 0;

const propertyAddress = [doc.propertyStreet, doc.propertyCity, doc.propertyState, doc.propertyZip]
  .filter(Boolean).join(', ') || 'N/A';

const discrepancies = [];
let validationStatus = 'Valid';

// Basic validation checks
if (!doc.buyerName)   discrepancies.push('Missing buyer name');
if (!doc.sellerName)  discrepancies.push('Missing seller name');
if (!doc.closingDate) discrepancies.push('Missing closing date');
if (purchasePrice <= 0) discrepancies.push('Missing or zero purchase price');

// Loan-to-value check
if (loanAmount > 0 && purchasePrice > 0) {
  const ltv = loanAmount / purchasePrice;
  if (ltv > 0.97) discrepancies.push(`LTV ratio ${(ltv*100).toFixed(1)}% exceeds 97% limit`);
}

// Signature checks
if (!doc.buyerSigned)  discrepancies.push('Buyer signature missing');
if (!doc.sellerSigned) discrepancies.push('Seller signature missing');
if (!doc.notarized)    discrepancies.push('Document not notarized');

// Cross-validate against previous docs for same file number
const hasRows = previousDocs.length > 0
  && previousDocs[0].json
  && Object.keys(previousDocs[0].json).length > 0;

if (hasRows && fileNumber !== 'N/A') {
  const relatedDocs = previousDocs.filter(r =>
    (r.json['File Number'] || '').trim() === fileNumber.trim()
  );
  relatedDocs.forEach(prev => {
    const prevPrice = parseFloat(prev.json['Amount'] || 0);
    if (prevPrice > 0 && purchasePrice > 0 && Math.abs(prevPrice - purchasePrice) > 100) {
      discrepancies.push(
        `Purchase price mismatch: this doc $${purchasePrice} vs previous $${prevPrice}`
      );
    }
    const prevBuyer = (prev.json['Buyer'] || '').toLowerCase();
    const thisBuyer = (doc.buyerName || '').toLowerCase();
    if (prevBuyer && thisBuyer && !thisBuyer.includes(prevBuyer.split(' ')[0])) {
      discrepancies.push(`Buyer name inconsistency: "${doc.buyerName}" vs previous "${prev.json['Buyer']}"`);
    }
  });
}

if (discrepancies.length > 0) {
  validationStatus = discrepancies.length >= 3 ? 'Failed' : 'Review Required';
}

return [{ json: {
  fileNumber,
  documentType:   docType,
  propertyAddress,
  buyerName:      doc.buyerName      || 'N/A',
  sellerName:     doc.sellerName     || 'N/A',
  lenderName:     doc.lenderName     || 'N/A',
  closingDate:    doc.closingDate    || 'N/A',
  purchasePrice,
  loanAmount,
  loanType:       doc.loanType       || 'N/A',
  interestRate:   doc.interestRate   || 0,
  cashToClose,
  closingCosts,
  sellerProceeds: doc.sellerProceeds || 0,
  buyerSigned:    doc.buyerSigned    ? 'Yes' : 'No',
  sellerSigned:   doc.sellerSigned   ? 'Yes' : 'No',
  notarized:      doc.notarized      ? 'Yes' : 'No',
  validationStatus,
  discrepancies:  discrepancies.join('; ') || 'None',
  discrepancyCount: discrepancies.length,
  fileName,
  fileId,
  processedAt: new Date().toISOString()
}}];

